const body = $input.first().json;

// Extract fields from Smartlead webhook payload
const leadEmail = body.to_email || body.lead_email || body.email || '';
const fromEmail = body.from_email || leadEmail;
const replyText = body.reply_text || body.message || body.body || '';
const subject = body.subject || '';
const campaignId = body.campaign_id || body.sl_campaign_id || '';
const leadId = body.lead_id || body.sl_lead_id || '';
const messageId = body.message_id || body.sl_message_id || '';
const businessId = body.business_id || '';
const leadName = body.lead_name || body.name || fromEmail.split('@')[0] || 'there';
const companyName = body.company_name || body.company || '';

// Clean reply text - strip quoted/forwarded content
let cleanReply = replyText;
const splitMarkers = ['On ', '-----Original Message', 'From:', '> On', '---'];
for (const marker of splitMarkers) {
  const idx = cleanReply.indexOf(marker);
  if (idx > 20) {
    cleanReply = cleanReply.substring(0, idx).trim();
  }
}

const replyLower = cleanReply.toLowerCase().trim();

// Intent detection
let intent = 'OTHER';

// UNSUBSCRIBE
const unsubWords = ['unsubscribe', 'remove me', 'opt out', 'stop emailing', 'take me off', 'do not contact', 'don\'t email', 'don\'t contact', 'remove from list', 'stop sending'];
if (unsubWords.some(w => replyLower.includes(w))) {
  intent = 'UNSUBSCRIBE';
}

// NEGATIVE
const negativeWords = ['not interested', 'no thanks', 'no thank you', 'pass', 'we\'re good', 'we are good', 'not for us', 'don\'t need', 'do not need', 'already have', 'go away', 'spam', 'junk'];
if (intent === 'OTHER' && negativeWords.some(w => replyLower.includes(w))) {
  intent = 'NEGATIVE';
}

// READY_FOR_DEMO
const demoWords = ['schedule a demo', 'book a demo', 'set up a call', 'let\'s talk', 'let\'s chat', 'let\'s connect', 'schedule a call', 'available for a call', 'i\'d love a demo', 'show me', 'when can we meet', 'book a time', 'interested in a demo', 'set up a meeting', 'love to see', 'would love to see', 'can we talk', 'can you show', 'free for a call', 'let me know when'];
if (intent === 'OTHER' && demoWords.some(w => replyLower.includes(w))) {
  intent = 'READY_FOR_DEMO';
}

// INTERESTED (general positive but not demo-ready)
const interestedWords = ['sounds interesting', 'tell me more', 'send more info', 'more details', 'more information', 'sounds good', 'interesting', 'curious', 'intrigued', 'we might need', 'could be useful', 'send me details'];
if (intent === 'OTHER' && interestedWords.some(w => replyLower.includes(w))) {
  intent = 'INTERESTED';
}

// PRICING_QUESTION
const pricingWords = ['how much', 'pricing', 'price', 'cost', 'rate', 'subscription', 'monthly fee', 'per month', 'annual', 'discount', 'free trial', 'trial period', 'what does it cost'];
if (intent === 'OTHER' && pricingWords.some(w => replyLower.includes(w))) {
  intent = 'PRICING_QUESTION';
}

// COMPETITOR_OBJECTION
const competitorWords = ['already using', 'we use', 'switched to', 'compared to', 'vs ', 'versus', 'better than', 'how is this different', 'what makes you different', 'why should we switch'];
if (intent === 'OTHER' && competitorWords.some(w => replyLower.includes(w))) {
  intent = 'COMPETITOR_OBJECTION';
}

// TECHNICAL_QUESTION
const techWords = ['integrate', 'integration', 'api', 'connect with', 'compatible', 'does it work with', 'support for', 'feature', 'functionality', 'how does it', 'can it', 'does it have', 'export', 'import', 'migrate', 'data'];
if (intent === 'OTHER' && techWords.some(w => replyLower.includes(w))) {
  intent = 'TECHNICAL_QUESTION';
}

return [{
  json: {
    intent,
    leadEmail: fromEmail,
    leadName,
    companyName,
    replyText: cleanReply,
    rawReplyText: replyText,
    subject,
    campaignId,
    leadId,
    messageId,
    businessId,
    receivedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;

// Dedup check: if messageId is empty, generate one from content hash
const messageId = data.messageId || '';
const leadEmail = data.leadEmail || '';
const businessId = data.businessId || '';

// We'll check Supabase for existing message_id and lead status
// For now, pass through with gate flags
return [{
  json: {
    ...data,
    _gateCheckNeeded: true,
    _dedupKey: messageId || `${leadEmail}-${Date.now()}`
  }
}];

const parsed = $('Parse Reply Intent').first().json;
const leadStatusResp = $('Check Lead Status (Supabase)').first().json;
const dedupResp = $('Check Message Dedup').first().json;

// Check dedup
const dedupResults = Array.isArray(dedupResp) ? dedupResp : [dedupResp];
if (dedupResults.length > 0 && dedupResults[0]?.id) {
  return [{ json: { ...parsed, _blocked: true, _blockReason: 'DUPLICATE_MESSAGE' } }];
}

// Check lead status
const leadResults = Array.isArray(leadStatusResp) ? leadStatusResp : [leadStatusResp];
const lead = leadResults.length > 0 ? leadResults[0] : null;
const terminalStatuses = ['converted', 'unsubscribed', 'rejected', 'paying'];

if (lead && terminalStatuses.includes(lead.status)) {
  return [{ json: { ...parsed, _blocked: true, _blockReason: `LEAD_STATUS_${lead.status.toUpperCase()}` } }];
}

// Passed gating
return [{ json: { ...parsed, _blocked: false, _blockReason: null, _leadDbId: lead?.id || null } }];

const data = $input.first().json;
const intent = data.intent;
const businessId = data.businessId;

// Build context lookup URLs
return [{
  json: {
    ...data,
    _prdUrl: `https://api.github.com/repos/Sluice-Organization/sluice-${businessId || 'orchestration'}/contents/memory-bank/prd.md`,
    _configUrl: `https://wjukfdziomnejtlmegvv.supabase.co/rest/v1/system_config?business_id=eq.${businessId}&select=*`,
    _intelUrl: `https://wjukfdziomnejtlmegvv.supabase.co/rest/v1/outreach_intelligence?business_id=eq.${businessId}&intent_type=in.(${intent},POSITIVE)&order=created_at.desc&limit=5`
  }
}];

const parsed = $('Prepare Context Lookup').first().json;
const prdResp = $('Fetch PRD from GitHub').first().json;
const configResp = $('Fetch Pricing (system_config)').first().json;
const intelResp = $('Fetch Outreach Intelligence').first().json;

// Decode PRD
let prdContent = 'No PRD available.';
try {
  if (prdResp.content) {
    prdContent = Buffer.from(prdResp.content, 'base64').toString('utf-8');
    if (prdContent.length > 2000) prdContent = prdContent.substring(0, 2000) + '...';
  }
} catch(e) { /* ignore */ }

// Extract pricing
let pricingInfo = 'No pricing info available.';
try {
  const configs = Array.isArray(configResp) ? configResp : [configResp];
  if (configs[0]?.pricing) {
    pricingInfo = JSON.stringify(configs[0].pricing);
  } else if (configs[0]) {
    pricingInfo = JSON.stringify(configs[0]);
  }
} catch(e) { /* ignore */ }

// Extract past successful replies
let pastReplies = 'No past intelligence available.';
try {
  const intel = Array.isArray(intelResp) ? intelResp : [intelResp];
  if (intel.length > 0 && intel[0]?.id) {
    pastReplies = intel.map(i => `Intent: ${i.intent_type}, Reply: ${(i.reply_sent || '').substring(0, 200)}`).join('\n');
  }
} catch(e) { /* ignore */ }

return [{
  json: {
    ...parsed,
    prdContext: prdContent,
    pricingContext: pricingInfo,
    pastRepliesContext: pastReplies
  }
}];

const data = $input.first().json;

const prompt = `You are a sales rep replying to a lead's email. Your job is to write a short, natural, helpful reply.

CRITICAL: Your response must not sound AI-generated. Use contractions. Vary sentence length. Be casual and direct. Never use these words: delve, leverage, utilize, harness, elevate, streamline, robust, seamless, cutting-edge, game-changer, innovative.

RULES (CRITICAL - follow every single one):
- Write like a real person. Short sentences. Casual but professional.
- NEVER use these words: delve, leverage, utilize, harness, elevate, empower, streamline, robust, seamless, cutting-edge, game-changer, innovative, revolutionize, best-in-class, holistic, synergy, paradigm, delighted, thrilled
- NEVER use em dashes (use regular dashes instead)
- ALWAYS use contractions (I'm, can't, won't, you're, we're, it's, don't, isn't)
- Vary sentence length (some 3 words, some 30)
- Include casual imperfections (start with "And" or "But", sentence fragments OK)
- NEVER start with "Great question!" or "Thanks for reaching out!" or "I appreciate your interest!"
- NEVER use exclamation marks more than once in the entire reply
- Keep it under 100 words
- Match the lead's tone and energy level
- Be direct and specific, not vague and salesy
- If you don't know something, say so honestly
- Keep paragraphs short (1-3 sentences)
- Write at 8th grade reading level
- Sign off with just a first name, no title

LEAD INFO:
- Name: ${data.leadName}
- Company: ${data.companyName}
- Their reply intent: ${data.intent}
- Their actual reply: "${data.replyText}"

BUSINESS CONTEXT:
Product info: ${data.prdContext.substring(0, 800)}
Pricing: ${data.pricingContext.substring(0, 500)}

PAST SUCCESSFUL REPLIES FOR REFERENCE:
${data.pastRepliesContext.substring(0, 500)}

INTENT-SPECIFIC GUIDANCE:
${data.intent === 'PRICING_QUESTION' ? 'Answer their pricing question directly. Include actual numbers if available. Offer to hop on a quick call if pricing is complex.' : ''}
${data.intent === 'COMPETITOR_OBJECTION' ? 'Acknowledge what they use. Don\'t trash competitors. Focus on 1-2 specific differences that matter for their use case.' : ''}
${data.intent === 'INTERESTED' ? 'Keep momentum. Ask a specific question about their current workflow to qualify them. Offer a concrete next step.' : ''}
${data.intent === 'TECHNICAL_QUESTION' ? 'Answer technically and accurately. If unsure, say "let me confirm with our team and get back to you." Don\'t make things up.' : ''}
${data.intent === 'OTHER' ? 'Read their message carefully and respond helpfully. If unclear, ask a clarifying question.' : ''}

Write ONLY the reply body. No subject line. No greeting like "Hi [Name]," - just the body text and sign-off.`;

return [{ json: { ...data, _llmPrompt: prompt } }];

const parsed = $('Build LLM Prompt').first().json;
const llmOutput = $('Generate Reply (LLM Chain)').first().json;

// Extract the generated reply text
const generatedReply = llmOutput.text || llmOutput.response || llmOutput.output || 'Sorry, I need a moment to get back to you on this. Will follow up shortly.';

// Clean up: add greeting
const greeting = `Hi ${parsed.leadName.split(' ')[0]},\n\n`;
const fullReply = greeting + generatedReply.trim();

return [{
  json: {
    ...parsed,
    generatedReply: fullReply
  }
}];

// Merge all paths back for logging
// Try to get data from whichever path executed
const parsed = $('Parse Reply Intent').first().json;

let replySent = '';
let action = '';

// Check which path we came from
try {
  const formatted = $('Format Generated Reply').first();
  if (formatted) {
    replySent = formatted.json.generatedReply || '';
    action = 'AI_REPLY_SENT';
  }
} catch(e) {}

if (!action) {
  // Must be from a fixed-reply path
  if (parsed.intent === 'UNSUBSCRIBE') {
    replySent = 'Done, you won\'t hear from us again.';
    action = 'UNSUBSCRIBE_CONFIRMED';
  } else if (parsed.intent === 'NEGATIVE') {
    replySent = 'Polite close sent.';
    action = 'NEGATIVE_CLOSED';
  } else if (parsed.intent === 'READY_FOR_DEMO') {
    replySent = 'Cal.com link sent.';
    action = 'DEMO_LINK_SENT';
  }
}

return [{
  json: {
    business_id: parsed.businessId,
    lead_email: parsed.leadEmail,
    lead_name: parsed.leadName,
    company_name: parsed.companyName,
    intent_type: parsed.intent,
    incoming_message: parsed.replyText,
    reply_sent: replySent,
    action: action,
    message_id: parsed.messageId,
    campaign_id: parsed.campaignId,
    created_at: new Date().toISOString()
  }
}];
